(79, 'لوبیا چیتی همدل - 450 گرم', NULL, 'خرید اینترنتی لوبیا چیتی همدل - 450 گرم  به همراه مقایسه، بررسی مشخصات و لیست قیمت امروز در فروشگاه اینترنتی فروشگاه اینترنتی هاوند', '', '/Pages_images/havand-products/6cac676fe2c7edfc6efed53455c21252d9694b60_1676359004.jpg', 1, '2026-01-29 03:16:45', 0, 32, '', 'sku-10666819', NULL, 0, 0, 0, 'SKU-10666819', 92, 47, 'درخواست مرجوع کردن کالا در این گروه کالایی با دلیل \"انصراف از خرید\" تنها در صورتی قابل تایید است که کالا در شرایط اولیه باشد (در صورت پلمب بودن، کالا نباید باز شده باشد).', '', '', 0, 0, 0, 0, '', 'قیمت و خرید لوبیا چیتی همدل - 450 گرم ', 0, NULL, NULL, 0, 's_product', 0.00, 0.00, 0.00, 0.00, NULL, '', NULL, 9, NULL, 0, NULL, 1, NULL, '2026-06-15 00:15:01'),
(80, 'سفره یکبار مصرف پنگوئن مدل رویال طرح پروانه رول 13 متری', NULL, 'خرید اینترنتی سفره یکبار مصرف پنگوئن مدل رویال طرح پروانه رول 13 متری با رنگبندی چند رنگ به همراه مقایسه، بررسی مشخصات و لیست قیمت امروز در فروشگاه اینترنتی فروشگاه اینترنتی هاوند', '', '/Pages_images/havand-products/a6da7611192e2a90628129411306090ee60497f2_1758923386.jpg', 1, '2026-02-01 06:46:42', 0, 305, '', 'sku-20538364', NULL, 0, 0, 0, 'SKU-20538364', 93, 48, 'درخواست مرجوع کردن کالا در گروه سفره یکبار مصرف با دلیل \"انصراف از خرید\" تنها در صورتی قابل تایید است که کالا در شرایط اولیه باشد (در صورت پلمپ بودن، کالا نباید باز شده باشد).', '', '', 0, 0, 0, 0, '', 'قیمت و خرید سفره یکبار مصرف پنگوئن مدل رویال طرح پروانه رول 13 متری', 0, NULL, NULL, 0, 's_product', 0.00, 0.00, 0.00, 0.00, NULL, NULL, NULL, 7, NULL, 0, NULL, 1, NULL, '2026-04-25 06:47:36'),
(81, 'رب انار کامبیز مقدار 250 گرم', NULL, 'خرید اینترنتی رب انار کامبیز مقدار 250 گرم به همراه مقایسه، بررسی مشخصات و لیست قیمت امروز در فروشگاه اینترنتی فروشگاه اینترنتی هاوند', '', '/Pages_images/havand-products/111861252.jpg', 1, '2026-02-01 06:53:20', 0, 42, '', 'sku-1748183', NULL, 0, 0, 0, 'SKU-1748183', 94, 49, '', '', 'Kambiz Pomegranate Paste 250gr', 0, 0, 0, 0, '', 'قیمت و خرید رب انار کامبیز مقدار 250 گرم', 5, NULL, NULL, 0, 's_product', 0.00, 0.00, 0.00, 0.00, NULL, NULL, NULL, 15, NULL, 0, NULL, 1, NULL, '2026-06-15 00:15:01'),
(82, 'ژل و صابون لیفت ابرو کاسه ای شیگلم', NULL, '', '<p style=\"text-align: justify;\"><br>ژل ابرو کاسه&zwnj;ای شیگلم (Sheglam Brow Gel) یک محصول حرفه&zwnj;ای برای مرتب&zwnj;سازی و فرم&zwnj;دهی ابروهاست که به&zwnj;صورت کاسه&zwnj;ای ارائه شده و با براش کوچک مخصوص می&zwnj;شه خیلی راحت استفاده&zwnj;اش کرد. این ژل ابرو بافتی سبک، کرمی و در عین حال ماندگار داره که به خوبی روی ابروها می&zwnj;شینه و اون&zwnj;ها رو پرتر، خوش&zwnj;فرم&zwnj;تر و طبیعی&zwnj;تر نشون می&zwnj;ده.</p>\n<p style=\"text-align: justify;\">فرمولاسیون این ژل به&zwnj;گونه&zwnj;ایه که بدون پوسته&zwnj;پوسته شدن یا ایجاد حس سنگینی، ابروها رو برای ساعت&zwnj;ها در حالت دلخواه نگه می&zwnj;داره. علاوه&zwnj;براین، تنوع رنگی خوبی داره و هم برای کسانی که ابروهای روشن دارن و هم برای ابروهای تیره مناسبه.</p>\n<p style=\"text-align: justify;\">برای آرایش&zwnj;های روزانه و حتی میکاپ&zwnj;های حرفه&zwnj;ای انتخاب خیلی خوبیه چون هم ابروها رو طبیعی پر می&zwnj;کنه و هم حالت شیک و تمیز به صورت می&zwnj;ده.</p>', '/Pages_images/havand-products/1770715931704--1-__20260210T093425_R344006.png', 1, '2026-02-09 21:40:44', 0, 390, '', 'sku-0087092430', NULL, 0, 0, 0, 'SKU-0087092430', 95, 50, 'درخواست مرجوع کردن کالا در این گروه کالایی با دلیل \"انصراف از خرید\" تنها در صورتی قابل تایید است که کالا در شرایط اولیه باشد (در صورت پلمب بودن، کالا نباید باز شده باشد).', '', NULL, 0, 0, 0, 0, '[]', '', 0, NULL, NULL, 0, 's_product', 0.00, 0.00, 0.00, 0.00, NULL, '', NULL, 59, NULL, 0, NULL, 1, NULL, '2026-06-14 05:44:53'),
(83, 'پالت سایه چشم دودو گرل مدل POCKET KIT', NULL, '', '<p style=\"text-align: justify;\"></p>\n<p style=\"text-align: justify;\">برند دودوگرل DoDo Girl در زمینه تولید انواع سایه برای چشم و ابرو در سال های اخیر فعالیت خوبی داشته و توانسته محصولات متنوعی روانه بازار کند. کیفیت مناسب در کنار قیمت های اقتصادی باعث شده تا محصولات این برند در ایران پر فروش گردند. در ادامه قصد داریم تا سایه چشم ۱۳ رنگ دودوگرل را به شما معرفی نماییم.</p>\n<p style=\"text-align: justify;\">یکی از محصولات جذاب برند DoDo Girl مدل POCKET KIT می باشد که در ۴ شماره مختلف تولید شده و هر پالت سایه دارای ۱۳ رنگ کاربردی و غالبا پر مصرف می باشد. این پالت سایه ترکیبی از رنگ های مات و براق بوده که دارای کیفیت خیلی خوب می باشد و به راحتی بر روی پوست قرار می گیرد و تا ساعت ها ماندگاری دارد. استفاده از از این سایه می تواند جلوه ای جذاب از شما در خاطر دیگران قرار دهد.</p>\n<p style=\"text-align: justify;\">از دیگر ویژگی های سایه ۱۳ رنگ دودوگرل DoDo Girl POCKET KIT اشغال فضای کم است که به راحتی میتوان در کیف های آرایش قرار داد تا در هر زمان بتوان از رنگ های زیبای آن استفاده نمود.</p>\n<p style=\"text-align: justify;\"></p>', '/Pages_images/havand-products/Untitled-127__20260210T163317_R984228.jpg', 1, '2026-02-10 16:22:40', 0, 365, '', 'sku-4055237', NULL, 0, 0, 0, 'SKU-4055237', 97, NULL, 'درخواست مرجوع کردن کالا در این گروه کالایی با دلیل \"انصراف از خرید\" تنها در صورتی قابل تایید است که کالا در شرایط اولیه باشد (در صورت پلمب بودن، کالا نباید باز شده باشد).', '', NULL, 0, 0, 0, 0, '[]', '', 0, NULL, NULL, 0, 'v_product', 0.00, 0.00, 0.00, 0.00, NULL, NULL, NULL, 18, NULL, 0, NULL, 1, NULL, '2026-04-17 11:34:21'),
(84, 'کرم پودر لورآل پاریس کاسه ای حجم 60 میلی لیتر', NULL, '', '<p style=\"text-align: justify;\"></p>\n<p style=\"text-align: justify;\"><span>از نمونه کرم گریم های پرطرفدار و پرفروش می توان کرم گریم حرفه ای لورآل را نام برد. این کرم مخصوص میکاپ های حرفه ای بوده و دارای پوشش دهی بسیار بالا و کاور فوق العاده می باشد که تمامی لک ها و جای جوش را بخوبی کاور نموده و پوستی صاف و یکدست را به شما هدیه خواهد داد. پوشش این کرم مات و مخملی بوده و از ایجاد چربی اضافه و براقیت پوست جلوگیری می نماید. همچنین کرم گریم حرفه ای لورآل حاوی ضدآفتاب با SPF15 می باشد که از پوست در مقابل تابش آفتاب و اشعه های مضر محیطی محافظت می نماید. این کرم ماندگاری بسیار بالایی داشته و برای استفاده در مهمانی و مجالس مناسب می باشد.</span></p>\n<p style=\"text-align: justify;\"></p>', '/Pages_images/havand-products/doushizeh__20260211T120254_R161825.jpg', 1, '2026-02-11 11:58:39', 0, 350, '', 'sku-1430927860', NULL, 0, 0, 0, 'SKU-1430927860', 101, NULL, 'درخواست مرجوع کردن کالا در این گروه کالایی با دلیل \"انصراف از خرید\" تنها در صورتی قابل تایید است که کالا در شرایط اولیه باشد (در صورت پلمب بودن، کالا نباید باز شده باشد).', '', 'L`OREAL Paris Make up Cream Foundation', 0, 0, 0, 0, '[]', '', 0, NULL, NULL, 0, 'v_product', 0.00, 0.00, 0.00, 0.00, NULL, NULL, NULL, 25, NULL, 0, NULL, 1, NULL, '2026-06-10 07:34:18'),
(85, 'رژگونه مایع رزبری Rose Berry', NULL, '', '<p style=\"text-align: justify;\"><span>استفاده از رژگونه مایع می&zwnj;تواند به تکمیل آرایش شما کمک کند و ظاهری طبیعی و جذابتر را در چهره ماندگار کند.</span><strong><span>&nbsp;</span>رژگونه مایع رزبری</strong><span>&nbsp;، یک رژگونه بسیار جذاب و آسان در استفاده است. فرمولاسیون مایع آن به راحتی با پوست ترکیب می&zwnj;شود و رنگدانه&zwnj;های غنی دارد. این رژگونه به پوست رنگ طبیعی و جذابی می&zwnj;بخشد. همچنین، بافت نرم و سبک آن باعث می&zwnj;شود پس از استفاده حس بسیار خوشایندی از آرایش خود داشته باشید.</span></p>\n<p style=\"text-align: justify;\"><span></span></p>\n<p style=\"text-align: justify;\">برخی از ویژگی&zwnj;های خاص<span>&nbsp;</span><strong>رژگونه رزبری</strong><span>&nbsp;</span>که یک ظاهر طبیعی و جذاب را برای شما می سازد، شامل موارد زیر است:</p>\n<p style=\"text-align: justify;\">رنگدانه قوی: این رژگونه دارای رنگدانه&zwnj;های قوی و غنی می باشد. با این ویژگی رنگ رژگونه روی گونه&zwnj;ها به خوبی ظاهر شده و پوشش مطلوبی ایجاد می کند.</p>\n<p style=\"text-align: justify;\">قابلیت مخلوط شدن: رژگونه به راحتی با پوست ترکیب شده و آن را به طور یکنواخت و موثری بر روی گونه&zwnj;ها پخش می شود.</p>\n<p style=\"text-align: justify;\">ماندگاری بالا: این محصول دارای ماندگاری طولانی است. به نحوی که تمام طول روز روی گونه ها ماندگار خواهد بود. این ویژگی مهم است تا آرایش شما تا انتهای روز حفظ شود و نیاز به بازسازی مکرر نداشته باشید.</p>', '/Pages_images/havand-products/ee140d34f34d73d9792be12b4fe2a49b5098347e_1702050579__20260213T164813_R158784.jpg', 1, '2026-02-11 15:31:32', 0, 352, '', 'sku-13643662', NULL, 0, 0, 0, 'SKU-13643662', 104, NULL, 'درخواست مرجوع کردن کالا در این گروه کالایی با دلیل \"انصراف از خرید\" تنها در صورتی قابل تایید است که کالا در شرایط اولیه باشد (در صورت پلمب بودن، کالا نباید باز شده باشد).', '', 'rose bery liquid plush', 0, 0, 0, 0, '[]', '', 0, NULL, NULL, 0, 'v_product', 0.00, 0.00, 0.00, 0.00, NULL, NULL, NULL, 5, NULL, 0, NULL, 1, NULL, '2026-05-17 21:37:34'),
(86, 'پرایمر توز مدل 7CC وزن 40 گرم', NULL, 'خرید اینترنتی پرایمر توز مدل 7CC وزن 40 گرم به همراه مقایسه، بررسی مشخصات و لیست قیمت امروز در فروشگاه اینترنتی هاوند', '<p style=\"text-align: justify;\"><span>پرایمر توز مدل 7CC، برای زیرسازی آرایش مناسب بوده و از چرب و براق شدن پوست جلوگیری می&zwnj;کند. این محصول به دلیل رنگی بودن، مشکلات پوست را خنثی کرده و برای برطرف کردن گودی و تیرگی دور چشم قابل استفاده است. پرایمر توز برای دوام بهتر آرایش و ماندگاری بیشتر استفاده می&zwnj;شود و جلوه نهایی مات و مخملی دارد.</span></p>', '/Pages_images/havand-products/tuz-color-rainbow-primer-40-ml-khanoumi--5--2024317104917987__20260211T153827_R348787.jpg', 1, '2026-02-11 15:32:05', 0, 359, '', 'sku-13935544', NULL, 0, 0, 0, 'SKU-13935544', 103, 51, '', '', 'Tuz Color Rainbow Primer 40 ml', 0, 0, 0, 0, '[]', 'قیمت و خرید پرایمر توز مدل 7CC وزن 40 گرم', 0, NULL, NULL, 0, 's_product', 0.00, 0.00, 0.00, 0.00, NULL, NULL, NULL, 6, NULL, 0, NULL, 1, NULL, '2026-04-26 01:37:21'),
(87, 'پنکک ضد آب ورسای 19 گرم Versai', NULL, 'خرید اینترنتی پنکیک ورسای مدل tow way cake به همراه مقایسه، بررسی مشخصات و لیست قیمت امروز در فروشگاه اینترنتی فروشگاه اینترنتی هاوند', '<p style=\"text-align: justify;\">پنکیک اصل ورسای&nbsp;مناسب برای پوست های چرب می باشد؛ زیرا فاقد چربی می باشد و از این رو&nbsp;<a href=\"https://banehluxx.com/product-category/cosmetic/face-makeup/pancake/\">بهترین پنکک برای پوست چرب</a>&nbsp;می باشد. و بر روی پوست برق نمی اندازد.&nbsp;پنکک مات ورسای&nbsp;کاملا ضد آب و ضد تعریق می باشد؛ یعنی با عرق کردن صورت پاک نمی شود. و ماندگاری بالایی دارد، و مناسب برای مهمانی ها می باشد.</p>\n<p style=\"text-align: justify;\">پنکک ضد آب ورسای&nbsp;رطوبت رسان و آبرسان پوست می باشد؛ از این رو آسیبی به پوست وارد نمی کند. پننکک ورسای دوکاره می باشد یعنی میتوان از آن برای زیرساز آرایش استفاده کرد و هم می توان به عنوان کاور نهایی از آن استفاده کرد.</p>', '/Pages_images/havand-products/a00c90c7-aa1e-440f-b03d-d92723dbfaeb__20260214T080734_R716766.png', 1, '2026-02-14 07:58:12', 0, 351, '', 'sku-5532363', NULL, 0, 0, 0, 'SKU-5532363', 107, 52, 'درخواست مرجوع کردن کالا در گروه پنکیک با دلیل \"انصراف از خرید\" تنها در صورتی قابل تایید است که کالا در شرایط اولیه باشد (در صورت پلمپ بودن، کالا نباید باز شده باشد).', '', 'Versai waterproof pancake 19 grams', 0, 0, 0, 0, '[]', 'قیمت و خرید پنکیک ورسای مدل tow way cake', 0, NULL, NULL, 0, 'v_product', 0.00, 0.00, 0.00, 0.00, NULL, NULL, NULL, 7, NULL, 0, NULL, 1, NULL, '2026-04-17 09:05:46'),
(88, 'لوسیون بدن دافی مدل آلوئه ورا حجم 470 میلی لیتر', NULL, 'خرید اینترنتی لوسیون بدن دافی مدل آلوئه ورا حجم 470 میلی لیتر به همراه مقایسه، بررسی مشخصات و لیست قیمت امروز در فروشگاه اینترنتی فروشگاه اینترنتی هاوند', '<p style=\"text-align: justify;\"><span>لوسیون بدن دافی مدل آلوئه ورا مغذی پوست بوده و برای استفاده روزانه مناسب است. این کرم بسیار ملایم است و برای پوست دست نیز کاربرد دارد. این محصول پوست بدن را تقویت و جوان&zwnj;سازی کرده، قرمزی و آفتاب&zwnj;سوختگی را تسکین می&zwnj;دهد و سلامتی را به پوست بازمی&zwnj;گرداند. لوسیون دافی حاوی ویتامین است و برای انواع پوست، حتی پوست آقایان، مناسب است.</span></p>', '/Pages_images/havand-products/104502019120257111__20260215T160317_R559299.webp', 1, '2026-02-15 10:56:11', 0, 414, '', 'sku-4526113', NULL, 0, 0, 0, 'SKU-4526113', NULL, 53, 'درخواست مرجوع کردن کالا در گروه لوسیون و روغن بدن با دلیل \"انصراف از خرید\" تنها در صورتی قابل تایید است که کالا در شرایط اولیه باشد (در صورت پلمپ بودن، کالا نباید باز شده باشد).', '', 'Body And Hand Lotion With Aloevera Extract', 0, 0, 0, 0, '', 'قیمت و خرید لوسیون بدن دافی مدل آلوئه ورا حجم 470 میلی لیتر', 0, NULL, NULL, 0, 's_product', 0.00, 0.00, 0.00, 0.00, NULL, '', NULL, 4, NULL, 0, NULL, 1, NULL, '2026-03-12 00:15:00'),
(89, 'لوسیون بدن دافی مدل اسطوخودوس حجم 470 میلی لیتر ', NULL, 'خرید اینترنتی لوسیون بدن دافی مدل اسطوخودوس حجم 470 میلی لیتر  به همراه مقایسه، بررسی مشخصات و لیست قیمت امروز در فروشگاه اینترنتی هاوند', '<p style=\"text-align: justify;\">لوسیون بدن دافی اسطوخودوس با مواد موثره&nbsp;<a target=\"_blank\" rel=\"noopener noreferrer\" href=\"https://darukade.com/mag/articles/suplement-9/know-more-about-hyaluronic-acid-and-its-benefits-830\"><span><strong>هیالورونیک اسید</strong></span></a>، شی باتر و روغن آرگان جهت نرم کردن و رطوبت رسانی به پوست دست و بدن در قالب بطری های پمپ دار&nbsp;470 میلی لیتر طراحی شده است. عصاره اسطوخودوس به کار رفته در فرمولاسیون این لوسیون، علاوه بر جلوگیری از بروز<span>&nbsp;</span><strong>خشکی</strong><span>&nbsp;</span><strong>پوست</strong>، با خاصیت<span>&nbsp;</span><strong>آنتی</strong><span>&nbsp;</span><strong>اکسیدانی</strong><span>&nbsp;</span>از پوست در برابر عوامل مضر محیطی به ویژه رادیکالهای آزاد محافظت می کند.&nbsp;</p>\n<p style=\"text-align: justify;\">به علاوه<span>&nbsp;</span><strong>ویتامین</strong><span>&nbsp;</span><strong>های</strong>&nbsp;B5،&nbsp;B3،&nbsp;C و&nbsp;A استفاده شده در فرمولاسیون لوسیون بدن دافی مدل اسطوخودوس، در تقویت بافت پوست و افزایش عملکرد سد دفاعی آن نقش به سزایی دارند. لوسیون بدن اسطوخودوس دافی بافت سبکی داشته و به سرعت جذب پوست می شود. &nbsp;این محصول برای استفاده روی<span>&nbsp;</span><strong>انواع پوست</strong><span>&nbsp;</span>مناسب بوده و به بهبود سلامت آن کمک می کند.&nbsp;</p>', '/Pages_images/havand-products/16562420192202592711__20260215T161123_R431625.webp', 1, '2026-02-15 16:08:03', 0, 414, '', 'sku-4526611', NULL, 0, 0, 0, 'SKU-4526611', 111, 53, 'درخواست مرجوع کردن کالا در گروه لوسیون و روغن بدن با دلیل \"انصراف از خرید\" تنها در صورتی قابل تایید است که کالا در شرایط اولیه باشد (در صورت پلمپ بودن، کالا نباید باز شده باشد).', '', 'Body And Hand Lotion With Lavender Extract', 0, 0, 0, 0, '', 'قیمت و خرید لوسیون بدن دافی مدل اسطوخودوس حجم 470 میلی لیتر ', 0, NULL, NULL, 0, 's_product', 0.00, 0.00, 0.00, 0.00, NULL, '', NULL, 9, '', 0, NULL, 1, NULL, '2026-05-20 00:06:01'),
(90, 'لوسیون بدن دافی مدل آواکادوو حجم 470 میلی لیتر', NULL, 'خرید اینترنتی لوسیون بدن دافی مدل آواکادوو حجم 470 میلی لیتر به همراه مقایسه، بررسی مشخصات و لیست قیمت امروز در فروشگاه اینترنتی فروشگاه اینترنتی هاوند', '<p style=\"text-align: justify;\"><span>لوسیون بدن دافی آووکادو یک محصول منحصر به فرد برای نرم و مرطوب کردن پوست&zwnj;های خشک و حساس است. این لوسیون با بهره&zwnj;گیری از ترکیبات غنی مانند روغن آووکادو، ویتامین C&nbsp;و شی باتر، پوست شما را تقویت، تغذیه و احیا می&zwnj;کند.&nbsp;فرمولاسیون این محصول با pH&nbsp;متناسب با پوست طراحی شده است تا بدون ایجاد آسیب به سد دفاعی پوست، رطوبت طبیعی آن را حفظ کند.&nbsp;</span></p>\n<p style=\"text-align: justify;\"><span>همچنین، لوسیون دست و بدن حاوی روغن آووکادو دافی به دلیل جذب سریع و سبک بودن، بدون ایجاد چربی ناخوشایند، برای استفاده روزانه بسیار مناسب است. این محصول فاقد پارابن و عطرهای مصنوعی است که آن را برای پوست&zwnj;های حساس نیز ایمن می&zwnj;کند.</span></p>\n<p style=\"text-align: justify;\"><span>روغن آووکادو سرشار از اسیدهای چرب اشباع نشده مانند اسید اولئیک است که به تقویت سد دفاعی پوست و حفظ رطوبت کمک می&zwnj;کند. همچنین ویتامین&zwnj;های A ،D&nbsp;و E&nbsp;موجود در آن دارای خواص آنتی&zwnj;اکسیدانی قوی هستند که از پوست در برابر اثرات مضر رادیکال&zwnj;های آزاد محافظت می&zwnj;کنند.</span></p>\n<p style=\"text-align: justify;\"><a target=\"_blank\" rel=\"noopener noreferrer\" href=\"https://darukade.com/mag/articles/skin-2/shea-butter-1754\"><span><strong>شی باتر</strong></span></a><strong><span>&nbsp;</span></strong><span>حاوی ترکیبات تری&zwnj;ترپنوئیدی است که به خواص ضدالتهابی و بازسازی&zwnj;کنندگی آن قدرت می&zwnj;بخشد. لایه محافظی که شی باتر روی پوست ایجاد می&zwnj;کند، از تبخیر آب جلوگیری کرده و باعث حفظ رطوبت عمقی می&zwnj;شود.&nbsp;این ترکیب به کاهش تحریکات پوستی و تسکین التهابات کمک می&zwnj;کند.</span></p>\n<p style=\"text-align: justify;\"><span>ویتامین C&nbsp;نقش کلیدی در افزایش تولید کلاژن دارد که برای بهبود خاصیت کشسانی و کاهش چین و چروک&zwnj;های پوست ضروری است. خاصیت آنتی&zwnj;اکسیدانی قوی ویتامین C&nbsp;به کاهش تیرگی&zwnj;ها و یکنواخت شدن رنگ پوست کمک می&zwnj;کند.&nbsp;در این محصول از فرم پایدار ویتامین C&nbsp;استفاده شده است تا تأثیر آن در کاهش لکه&zwnj;های پوستی و روشن&zwnj;کنندگی حفظ شود.</span></p>\n<p style=\"text-align: justify;\"><span>استفاده مداوم از&nbsp;<strong>لوسیون بدن دافی آووکادو</strong>&nbsp;نه تنها به سلامت و زیبایی پوست شما کمک می&zwnj;کند، بلکه به دلیل ترکیبات طبیعی و اثرات اثبات&zwnj;شده، انتخابی ایمن و مؤثر برای تمامی اعضای خانواده است. با خرید این محصول، نرمی، لطافت و شادابی پوست خود را تضمین کنید.</span></p>', '/Pages_images/havand-products/945721830202552111__20260215T161942_R749955.webp', 1, '2026-02-15 16:17:43', 0, 414, '', 'sku-4526345', NULL, 0, 0, 0, 'SKU-4526345', 112, 53, 'درخواست مرجوع کردن کالا در گروه لوسیون و روغن بدن با دلیل \"انصراف از خرید\" تنها در صورتی قابل تایید است که کالا در شرایط اولیه باشد (در صورت پلمپ بودن، کالا نباید باز شده باشد).', '', 'Body And Hand Lotion With Avocado Oil', 0, 0, 0, 0, '', 'قیمت و خرید لوسیون بدن دافی مدل آواکادوو حجم 470 میلی لیتر', 0, NULL, NULL, 0, 's_product', 0.00, 0.00, 0.00, 0.00, NULL, NULL, NULL, 12, NULL, 0, NULL, 1, NULL, '2026-06-10 13:54:18'),
